B.a5_=new A.n(B.j,["In the name of Allah and with the blessings of Allah.","\u0628\u0633\u0645 \u0627\u0644\u0644\u0647 \u0648\u0639\u0644\u0649 \u0628\u0631\u0643\u0629 \u0627\u0644\u0644\u0647","\u0412\u043e \u0438\u043c\u044f \u0410\u043b\u043b\u0430\u0445\u0430 \u0438 \u0441 \u0431\u043b\u0430\u0433\u043e\u0441\u043b\u043e\u0432\u0435\u043d\u0438\u0435\u043c \u0410\u043b\u043b\u0430\u0445\u0430.","\u0905\u0932\u094d\u0932\u093e\u0939 \u0915\u0947 \u0928\u093e\u092e \u0938\u0947 \u0914\u0930 \u0905\u0932\u094d\u0932\u093e\u0939 \u0915\u0940 \u092c\u0930\u0915\u0924 \u0938\u0947\u0964","Dengan nama Allah dan dengan berkah Allah.","\u4ee5\u771f\u4e3b\u4e4b\u540d\uff0c\u51ed\u771f\u4e3b\u7684\u5409\u5e86\u3002","Im Namen Allahs und mit dem Segen Allahs.","In de naam van Allah en met de zegeningen van Allah.","Au nom d'Allah et avec les b\xe9n\xe9dictions d'Allah.","En el nombre de Allah y con las bendiciones de Allah."],t.w)
B.a1Z=new A.n(B.cZ,["food",B.Qc,"\u0628\u0650\u0633\u0652\u0645\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0648\u064e\u0639\u064e\u0644\u064e\u0649 \u0628\u064e\u0631\u064e\u0643\u064e\u0629\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u0650","Bismillahi wa ala barakatillah.",B.a5_],t.yf)
B.Q6=new A.b3(58007,!1)
B.a4R=new A.n(B.j,["Glory to Him who has subjected this to us, and we could never have it. And to our Lord, surely, we are to return.","\u0633\u0628\u062d\u0627\u0646 \u0627\u0644\u0630\u064a \u0633\u062e\u0631 \u0644\u0646\u0627 \u0647\u0630\u0627 \u0648\u0645\u0627 \u0643\u0646\u0627 \u0644\u0647 \u0645\u0642\u0631\u0646\u064a\u0646 \u0648\u0625\u0646\u0627 \u0625\u0644\u0649 \u0631\u0628\u0646\u0627 \u0644\u0645\u0646\u0642\u0644\u0628\u0648\u0646","\u041f\u0440\u0435\u0447\u0438\u0441\u0442 \u0422\u043e\u0442, \u041a\u0442\u043e \u043f\u043e\u0434\u0447\u0438\u043d\u0438\u043b \u043d\u0430\u043c \u044d\u0442\u043e, \u0432\u0435\u0434\u044c \u0441\u0430\u043c\u0438 \u043c\u044b \u043d\u0435 \u043c\u043e\u0433\u043b\u0438 \u0431\u044b \u044d\u0442\u043e\u0433\u043e. \u0418 \u043c\u044b \u043a \u043d\u0430\u0448\u0435\u043c\u0443 \u0413\u043e\u0441\u043f\u043e\u0434\u0443 \u0432\u0435\u0440\u043d\u0451\u043c\u0441\u044f.","\u092a\u093e\u0915 \u0939\u0948 \u0935\u0939 \u091c\u093f\u0938\u0928\u0947 \u0907\u0938\u0947 \u0939\u092e\u093e\u0930\u0947 \u0935\u0936 \u092e\u0947\u0902 \u0915\u093f\u092f\u093e \u0914\u0930 \u0939\u092e \u0907\u0938\u0947 \u0935\u0936 \u092e\u0947\u0902 \u0915\u0930\u0928\u0947 \u0915\u0940 \u0924\u093e\u0915\u093c\u0924 \u0928\u0939\u0940\u0902 \u0930\u0916\u0924\u0947\u0964 \u0914\u0930 \u0939\u092e \u0905\u092a\u0928\u0947 \u0930\u092c \u0915\u0940 \u0913\u0930 \u0932\u094c\u091f\u0928\u0947 \u0935\u093e\u0932\u0947 \u0939\u0948\u0902\u0964","Maha Suci yang menundukkan ini untuk kami, padahal kami tidak mampu menguasainya. Dan sesungguhnya kami akan kembali kepada Tuhan kami.","\u8d5e\u7f8e\u90a3\u4e3a\u6211\u4eec\u5236\u670d\u8fd9\u4e00\u5207\u7684\u4e3b\uff0c\u6211\u4eec\u81ea\u5df1\u65e0\u6cd5\u505a\u5230\u3002\u6211\u4eec\u786e\u5c06\u5f52\u4e8e\u6211\u4eec\u7684\u4e3b\u3002","Gepriesen sei Der, Der uns dieses dienstbar gemacht hat, und wir h\xe4tten es nicht vermocht. Und zu unserem Herrn werden wir zur\xfcckkehren.","Glorie aan Degene Die dit voor ons onderworpen heeft, wij hadden het niet kunnen doen. En tot onze Heer keren wij terug.","Gloire \xe0 Celui qui a mis ceci \xe0 notre service, nous n'aurions pas pu le faire. Et c'est vers notre Seigneur que nous retournerons.","Gloria a Quien ha sometido esto para nosotros, que no podr\xedamos haberlo hecho. Y a nuestro Se\xf1or ciertamente regresaremos."],t.w)
B.a1U=new A.n(B.cZ,["travel",B.Q6,"\u0633\u064f\u0628\u0652\u062d\u064e\u0627\u0646\u064e \u0627\u0644\u064e\u0651\u0630\u0650\u064a \u0633\u064e\u062e\u064e\u0651\u0631\u064e \u0644\u064e\u0646\u064e\u0627 \u0647\u064e\u0630\u064e\u0627 \u0648\u064e\u0645\u064e\u0627 \u0643\u064f\u0646\u064e\u0651\u0627 \u0644\u064e\u0647\u064f \u0645\u064f\u0642\u0652\u0631\u0650\u0646\u0650\u064a\u0646\u064e \u0648\u064e\u0625\u0650\u0646\u064e\u0651\u0627 \u0625\u0650\u0644\u064e\u0649 \u0631\u064e\u0628\u0650\u0651\u0646\u064e\u0627 \u0644\u064e\u0645\u064f\u0646\u0652\u0642\u064e\u0644\u0650\u0628\u064f\u0648\u0646\u064e","Subhanal-ladhi sakh-khara lana hadha wa ma kunna lahu muqrinin, wa inna ila Rabbina lamunqalibun.",B.a4R],t.yf)
B.a5M=new A.n(B.j,["O Allah, open the gates of Your mercy for me.","\u0627\u0644\u0644\u0647\u0645 \u0627\u0641\u062a\u062d \u0644\u064a \u0623\u0628\u0648\u0627\u0628 \u0631\u062d\u0645\u062a\u0643","\u041e \u0410\u043b\u043b\u0430\u0445, \u043e\u0442\u043a\u0440\u043e\u0439 \u0434\u043b\u044f \u043c\u0435\u043d\u044f \u0432\u0440\u0430\u0442\u0430 \u0422\u0432\u043e\u0435\u0439 \u043c\u0438\u043b\u043e\u0441\u0442\u0438.","\u0910 \u0905\u0932\u094d\u0932\u093e\u0939, \u092e\u0947\u0930\u0947 \u0932\u093f\u090f \u0905\u092a\u0928\u0940 \u0930\u0939\u092e\u0924 \u0915\u0947 \u0926\u0930\u0935\u093e\u091c\u093c\u0947 \u0916\u094b\u0932 \u0926\u0947\u0964","Ya Allah, bukakanlah pintu-pintu rahmat-Mu untukku.","\u771f\u4e3b\u554a\uff0c\u8bf7\u4e3a\u6211\u6253\u5f00\u4f60\u6148\u60b2\u4e4b\u95e8\u3002","O Allah, \xf6ffne mir die Tore Deiner Barmherzigkeit.","O Allah, open voor mij de deuren van Uw genade.","\xd4 Allah, ouvre-moi les portes de Ta mis\xe9ricorde.","Oh Allah, abre para m\xed las puertas de Tu misericordia."],t.w)
B.a1X=new A.n(B.cZ,["mosque",B.fw,"\u0627\u0644\u0644\u064e\u0651\u0647\u064f\u0645\u064e\u0651 \u0627\u0641\u0652\u062a\u064e\u062d\u0652 \u0644\u0650\u064a \u0623\u064e\u0628\u0652\u0648\u064e\u0627\u0628\u064e \u0631\u064e\u062d\u0652\u0645\u064e\u062a\u0650\u0643\u064e","Allahumma iftah li abwaba rahmatik.",B.a5M],t.yf)
B.Qf=new A.b3(58774,!1)
B.a5b=new A.n(B.j,["In the name of Allah with whose name nothing can cause harm in the earth or in the heavens. He is the All-Hearing, the All-Knowing.","\u0628\u0633\u0645 \u0627\u0644\u0644\u0647 \u0627\u0644\u0630\u064a \u0644\u0627 \u064a\u0636\u0631 \u0645\u0639 \u0627\u0633\u0645\u0647 \u0634\u064a\u0621 \u0641\u064a \u0627\u0644\u0623\u0631\u0636 \u0648\u0644\u0627 \u0641\u064a \u0627\u0644\u0633\u0645\u0627\u0621 \u0648\u0647\u0648 \u0627\u0644\u0633\u0645\u064a\u0639 \u0627\u0644\u0639\u0644\u064a\u0645","\u0412\u043e \u0438\u043c\u044f \u0410\u043b\u043b\u0430\u0445\u0430, \u0441 \u0438\u043c\u0435\u043d\u0435\u043c \u041a\u043e\u0442\u043e\u0440\u043e\u0433\u043e \u043d\u0438\u0447\u0442\u043e \u043d\u0435 \u043f\u0440\u0438\u0447\u0438\u043d\u0438\u0442 \u0432\u0440\u0435\u0434\u0430 \u043d\u0438 \u043d\u0430 \u0437\u0435\u043c\u043b\u0435, \u043d\u0438 \u043d\u0430 \u043d\u0435\u0431\u0435\u0441\u0430\u0445. \u041e\u043d \u0412\u0441\u0435\u0441\u043b\u044b\u0448\u0430\u0449\u0438\u0439, \u0412\u0441\u0435\u0437\u043d\u0430\u044e\u0449\u0438\u0439.","\u0905\u0932\u094d\u0932\u093e\u0939 \u0915\u0947 \u0928\u093e\u092e \u0938\u0947, \u091c\u093f\u0938\u0915\u0947 \u0928\u093e\u092e \u0915\u0947 \u0938\u093e\u0925 \u091c\u093c\u092e\u0940\u0928 \u0914\u0930 \u0906\u0938\u092e\u093e\u0928 \u092e\u0947\u0902 \u0915\u094b\u0908 \u091a\u0940\u091c\u093c \u0928\u0941\u0915\u0938\u093e\u0928 \u0928\u0939\u0940\u0902 \u092a\u0939\u0941\u0901\u091a\u093e \u0938\u0915\u0924\u0940\u0964 \u0935\u0939 \u0938\u092c \u0938\u0941\u0928\u0928\u0947 \u0935\u093e\u0932\u093e, \u0938\u092c \u091c\u093e\u0928\u0928\u0947 \u0935\u093e\u0932\u093e \u0939\u0948\u0964","Dengan nama Allah yang dengan nama-Nya tidak ada sesuatu pun yang membahayakan di bumi dan di langit. Dia Maha Mendengar lagi Maha Mengetahui.","\u4ee5\u771f\u4e3b\u4e4b\u540d\uff0c\u51ed\u4ed6\u7684\u540d\uff0c\u5929\u5730\u95f4\u6ca1\u6709\u4efb\u4f55\u4e8b\u7269\u80fd\u9020\u6210\u4f24\u5bb3\u3002\u4ed6\u662f\u5168\u542c\u7684\uff0c\u5168\u77e5\u7684\u3002","Im Namen Allahs, mit dessen Namen nichts auf Erden und im Himmel Schaden anrichten kann. Er ist der Allh\xf6rende, der Allwissende.","In de naam van Allah, met wiens naam niets op aarde of in de hemelen schade kan berokkenen. Hij is de Alhorende, de Alwetende.","Au nom d'Allah, avec le nom duquel rien ne peut nuire sur terre ni dans les cieux. Il est l'Audient, l'Omniscient.","En el nombre de Allah, con cuyo nombre nada puede causar da\xf1o en la tierra ni en los cielos. \xc9l es el que Todo lo Oye, el Omnisciente."],t.w)
B.a1V=new A.n(B.cZ,["protection",B.Qf,"\u0628\u0650\u0633\u0652\u0645\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0627\u0644\u064e\u0651\u0630\u0650\u064a \u0644\u064e\u0627 \u064a\u064e\u0636\u064f\u0631\u064f\u0651 \u0645\u064e\u0639\u064e \u0627\u0633\u0652\u0645\u0650\u0647\u0650 \u0634\u064e\u064a\u0652\u0621\u064c \u0641\u0650\u064a \u0627\u0644\u0652\u0623\u064e\u0631\u0652\u0636\u0650 \u0648\u064e\u0644\u064e\u0627 \u0641\u0650\u064a \u0627\u0644\u0633\u064e\u0651\u0645\u064e\u0627\u0621\u0650 \u0648\u064e\u0647\u064f\u0648\u064e \u0627\u0644\u0633\u064e\u0651\u0645\u0650\u064a\u0639\u064f \u0627\u0644\u0652\u0639\u064e\u0644\u0650\u064a\u0645\u064f","Bismillahil-ladhi la yadurru ma'asmihi shay'un fil-ardi wa la fis-sama'i wa huwas-Sami'ul-Alim.",B.a5b],t.yf)
B.a4T=new A.n(B.j,["My Lord, forgive me and accept my repentance. You are the Acceptor of Repentance, the Most Merciful.","\u0631\u0628 \u0627\u063a\u0641\u0631 \u0644\u064a \u0648\u062a\u0628 \u0639\u0644\u064a\u0651 \u0625\u0646\u0643 \u0623\u0646\u062a \u0627\u0644\u062a\u0648\u0627\u0628 \u0627\u0644\u0631\u062d\u064a\u0645","\u0413\u043e\u0441\u043f\u043e\u0434\u044c \u043c\u043e\u0439, \u043f\u0440\u043e\u0441\u0442\u0438 \u043c\u0435\u043d\u044f \u0438 \u043f\u0440\u0438\u043c\u0438 \u043c\u043e\u0451 \u043f\u043e\u043a\u0430\u044f\u043d\u0438\u0435. \u0422\u044b \u2014 \u041f\u0440\u0438\u043d\u0438\u043c\u0430\u044e\u0449\u0438\u0439 \u043f\u043e\u043a\u0430\u044f\u043d\u0438\u0435, \u041c\u0438\u043b\u043e\u0441\u0435\u0440\u0434\u043d\u044b\u0439.","\u092e\u0947\u0930\u0947 \u0930\u092c, \u092e\u0941\u091d\u0947 \u092e\u093e\u092b\u093c \u0915\u0930 \u0914\u0930 \u092e\u0947\u0930\u0940 \u0924\u094c\u092c\u093e \u0915\u092c\u0942\u0932 \u0915\u0930\u0964 \u092c\u0947\u0936\u0915 \u0924\u0942 \u0924\u094c\u092c\u093e \u0915\u092c\u0942\u0932 \u0915\u0930\u0928\u0947 \u0935\u093e\u0932\u093e, \u0930\u0939\u092e \u0915\u0930\u0928\u0947 \u0935\u093e\u0932\u093e \u0939\u0948\u0964","Ya Tuhanku, ampunilah aku dan terimalah taubatku. Sesungguhnya Engkau Maha Penerima taubat lagi Maha Penyayang.","\u6211\u7684\u4e3b\u554a\uff0c\u8bf7\u539f\u8c05\u6211\uff0c\u63a5\u53d7\u6211\u7684\u5fcf\u6094\u3002\u4f60\u662f\u63a5\u53d7\u5fcf\u6094\u7684\uff0c\u81f3\u6148\u7684\u3002","Mein Herr, vergib mir und nimm meine Reue an. Du bist der Reue-Annehmende, der Barmherzige.","Mijn Heer, vergeef mij en aanvaard mijn berouw. U bent de Aanvaardder van Berouw, de Meest Barmhartige.","Mon Seigneur, pardonne-moi et accepte mon repentir. Tu es l'Accueillant au repentir, le Mis\xe9ricordieux.","Se\xf1or m\xedo, perd\xf3name y acepta mi arrepentimiento. T\xfa eres el que Acepta el arrepentimiento, el M\xe1s Misericordioso."],t.w)
B.a20=new A.n(B.cZ,["forgiveness",B.qf,"\u0631\u064e\u0628\u0650\u0651 \u0627\u063a\u0652\u0641\u0650\u0631\u0652 \u0644\u0650\u064a \u0648\u064e\u062a\u064f\u0628\u0652 \u0639\u064e\u0644\u064e\u064a\u064e\u0651 \u0625\u0650\u0646\u064e\u0651\u0643\u064e \u0623\u064e\u0646\u0652\u062a\u064e \u0627\u0644\u062a\u064e\u0651\u0648\u064e\u0651\u0627\u0628\u064f \u0627\u0644\u0631\u064e\u0651\u062d\u0650\u064a\u0645\u064f","Rabbighfir li wa tub alayya, innaka Antat-Tawwabur-Rahim.",B.a4T],t.yf)
