B.aaW=new A.f5(55,"\u0627\u0644\u0631\u062d\u0645\u0646","Ar-Rahman",78,"\u0628\u0650\u0633\u0652\u0645\u0650 \u0627\u0644\u0644\u064e\u0651\u0647\u0650 \u0627\u0644\u0631\u064e\u0651\u062d\u0652\u0645\u064e\u0670\u0646\u0650 \u0627\u0644\u0631\u064e\u0651\u062d\u0650\u064a\u0645\u0650\n\u0627\u0644\u0631\u064e\u0651\u062d\u0652\u0645\u064e\u0670\u0646\u064f \ufd3f\u0661\ufd3e\n\u0639\u064e\u0644\u064e\u0651\u0645\u064e \u0627\u0644\u0652\u0642\u064f\u0631\u0652\u0622\u0646\u064e \ufd3f\u0662\ufd3e\n\u062e\u064e\u0644\u064e\u0642\u064e \u0627\u0644\u0652\u0625\u0650\u0646\u0633\u064e\u0627\u0646\u064e \ufd3f\u0663\ufd3e\n\u0639\u064e\u0644\u064e\u0651\u0645\u064e\u0647\u064f \u0627\u0644\u0652\u0628\u064e\u064a\u064e\u0627\u0646\u064e \ufd3f\u0664\ufd3e\n...",B.a29)
B.a28=new A.n(B.bM,["Allah - there is no deity except Him, the Ever-Living, the Sustainer of existence. Neither drowsiness overtakes Him nor sleep. To Him belongs whatever is in the heavens and whatever is on the earth. Who is it that can intercede with Him except by His permission? He knows what is before them and what will be after them, and they encompass not a thing of His knowledge except for what He wills. His Kursi extends over the heavens and the earth, and their preservation tires Him not. And He is the Most High, the Most Great.","Allah, O'ndan ba\u015fka ilah yoktur. Hayy ve Kayyum'dur. O'nu ne uyuklama tutar ne uyku. G\xf6klerde ve yerde ne varsa O'nundur. \u0130zni olmadan O'nun kat\u0131nda kim \u015fefaat edebilir? O, kullar\u0131n\u0131n \xf6nlerindekini ve arkalar\u0131ndakini bilir. Onlar O'nun ilminden, O'nun diledi\u011fi kadar\u0131ndan ba\u015fka bir \u015fey kavrayamazlar. O'nun k\xfcrs\xfcs\xfc g\xf6kleri ve yeri kaplam\u0131\u015ft\u0131r. Onlar\u0131n korunmas\u0131 O'na g\xfc\xe7 gelmez. O, y\xfccedir, b\xfcy\xfckt\xfcr."],t.w)
